{"content": "use crate::api::*;
use std::sync::RwLock;

/// VectorDB stores 128-dimensional vectors with unique IDs.
/// Uses parallel brute-force search with SIMD-accelerated distance computation.
pub struct VectorDB {
    // Vector data: (id, vector) pairs
    vectors: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vectors = self.vectors.write().unwrap();
        vectors.push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut stored = self.vectors.write().unwrap();
        let count = vectors.len();
        stored.extend(vectors);
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vectors = self.vectors.read().unwrap();

        if vectors.is_empty() {
            return Vec::new();
        }

        let k = top_k as usize;
        let query_vec = query.to_vec();

        // Use parallel search with rayon
        let mut results: Vec<(u64, f64)> = vectors
            .par_iter()
            .map(|(id, vec)| {
                let dist = crate::distance::l2_distance(&query_vec, vec);
                (*id, dist)
            })
            .collect();

        // Sort by distance and take top k
        results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));

        results
            .into_iter()
            .take(k)
            .map(|(id, distance)| SearchResult { id, distance })
            .collect()
    }
}
