{"content": "use crate::api::*;
use std::sync::{RwLock, Mutex};
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Reverse;

/// Custom wrapper to handle f32 ordering in BinaryHeap
#[derive(Debug)]
struct Distance(f32);

impl PartialEq for Distance {
    fn eq(&self, other: &Self) -> bool {
        self.0 == other.0
    }
}

impl Eq for Distance {}

impl PartialOrd for Distance {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        self.0.partial_cmp(&other.0)
    }
}

impl Ord for Distance {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.0.partial_cmp(&other.0).unwrap_or(std::cmp::Ordering::Equal)
    }
}

/// VectorDB stores 128-dimensional vectors with unique IDs.
/// Uses parallel brute-force search with SIMD-accelerated distance computation.
pub struct VectorDB {
    // Vector data: (id, vector) pairs
    vectors: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vectors = self.vectors.write().unwrap();
        vectors.push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut stored = self.vectors.write().unwrap();
        let count = vectors.len();
        stored.extend(vectors);
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vectors = self.vectors.read().unwrap();

        if vectors.is_empty() {
            return Vec::new();
        }

        let k = top_k as usize;

        // Use a binary heap to keep only top-k results
        // Use f32 for heap to avoid Ord issues with f64
        let heap: Mutex<BinaryHeap<(Distance, u64)>> = Mutex::new(BinaryHeap::with_capacity(k + 1));

        // Use parallel search with rayon
        vectors.par_iter().for_each(|(id, vec)| {
            let dist_f64 = crate::distance::l2_distance(query, vec);
            let dist = Distance(dist_f64 as f32);  // Convert to f32 for heap
            let mut heap_guard = heap.lock().unwrap();
            if heap_guard.len() < k {
                heap_guard.push((dist, *id));
            } else if let Some((max_dist, _)) = heap_guard.peek() {
                if dist < *max_dist {
                    heap_guard.pop();
                    heap_guard.push((dist, *id));
                }
            }
        });

        // Extract results from heap and sort
        let heap_data = heap.into_inner().unwrap();
        let mut results: Vec<(u64, f64)> = heap_data
            .into_iter()
            .map(|(Distance(dist), id)| (id, dist as f64))
            .collect();

        // Sort by distance ascending
        results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));

        results
            .into_iter()
            .map(|(id, distance)| SearchResult { id, distance })
            .collect()
    }
}
