{"content": "use crate::api::*;
use std::sync::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Reverse;

/// Wrapper for f32 to use in BinaryHeap
#[derive(Debug)]
struct Dist(f32);

impl PartialEq for Dist {
    fn eq(&self, other: &Self) -> bool {
        self.0 == other.0
    }
}

impl Eq for Dist {}

impl PartialOrd for Dist {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        self.0.partial_cmp(&other.0)
    }
}

impl Ord for Dist {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.0.partial_cmp(&other.0).unwrap_or(std::cmp::Ordering::Equal)
    }
}

/// VectorDB stores 128-dimensional vectors with unique IDs.
/// Uses SIMD-accelerated distance computation with parallel search.
/// Memory layout: flat contiguous storage for better cache performance.
pub struct VectorDB {
    // Vector IDs
    ids: RwLock<Vec<u64>>,
    // Flat vector data: [v1_dim0, v1_dim1, ..., v1_dim127, v2_dim0, ...]
    vectors: RwLock<Vec<f32>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            ids: RwLock::new(Vec::new()),
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids = self.ids.write().unwrap();
        let mut vectors = self.vectors.write().unwrap();
        ids.push(id);
        vectors.extend(vector);
    }

    pub fn bulk_insert(&self, new_vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids = self.ids.write().unwrap();
        let mut vectors = self.vectors.write().unwrap();
        let count = new_vectors.len();
        for (id, vec) in new_vectors {
            ids.push(id);
            vectors.extend(vec);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read().unwrap();
        let vectors = self.vectors.read().unwrap();

        if vectors.is_empty() {
            return Vec::new();
        }

        let k = top_k as usize;
        let dim = 128;
        let count = ids.len();
        let query_vec = query.to_vec();

        // Use a binary heap to track top-k during parallel processing
        // We'll collect all results first, then use heap for top-k
        // Actually, for better parallelism, let's collect all and use heap at the end

        // Compute distances in parallel
        let results: Vec<(u64, f64)> = (0..count)
            .into_par_iter()
            .map(|i| {
                let dist = unsafe {
                    let vec_ptr = vectors.as_ptr().add(i * dim);
                    let vec_slice = std::slice::from_raw_parts(vec_ptr, dim);
                    crate::distance::l2_distance(&query_vec, vec_slice)
                };
                (ids[i], dist)
            })
            .collect();

        // Use binary heap to get top-k efficiently
        // Create a min-heap (smallest distance on top)
        let mut heap: BinaryHeap<Reverse<(Dist, u64)>> = BinaryHeap::with_capacity(k + 1);

        for (id, dist) in results {
            let dist_f32 = Dist(dist as f32);
            if heap.len() < k {
                heap.push(Reverse((dist_f32, id)));
            } else if let Some(Reverse((Dist(max_dist), _))) = heap.peek() {
                if dist_f32 < *max_dist {
                    heap.pop();
                    heap.push(Reverse((dist_f32, id)));
                }
            }
        }

        // Extract and sort results
        let mut results: Vec<(u64, f64)> = heap
            .into_iter()
            .map(|Reverse((Dist(dist), id))| (id, dist as f64))
            .collect();

        // Sort by distance ascending
        results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));

        results
            .into_iter()
            .map(|(id, distance)| SearchResult { id, distance })
            .collect()
    }
}
