/// VectorDB stores 128-dimensional vectors with unique IDs.
/// Uses parallel brute-force search with SIMD-accelerated distance computation.
pub struct VectorDB {
    // Vector data: (id, vector) pairs
    vectors: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vectors = self.vectors.write().unwrap();
        vectors.push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut stored = self.vectors.write().unwrap();
        let count = vectors.len();
        stored.extend(vectors);
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vectors = self.vectors.read().unwrap();

        if vectors.is_empty() {
            return Vec::new();
        }

        let k = top_k as usize;
        let query_vec = query.to_vec();

        // Use parallel search with rayon - collect all distances
        let mut results: Vec<(u64, f64)> = vectors
            .par_iter()
            .map(|(id, vec)| {
                let dist = crate::distance::l2_distance(&query_vec, vec);
                (*id, dist)
            })
            .collect();

        // Use nth_element (partially sort) instead of full sort
        // This is O(n) average case instead of O(n log n)
        if results.len() > k {
            let mid = results.as_mut_slice().partition_at_index(k);
            // mid is now the kth element, elements [0..k) are <= mid, [k..end) are >= mid

            // We need the top-k smallest, so we need to re-partition
            // Actually, partition_at_index gives us elements < pivot for [0..k) 
            // and elements >= pivot for [k..end)

            // But we need sorted results, so let's just do a partial sort
            results.select_nth_unstable_by(k, |a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));

            // Now elements [0..k) are the k smallest (unsorted within themselves)
            // Sort just the top k elements
            results[..k].sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));

            results
                .into_iter()
                .take(k)
                .map(|(id, distance)| SearchResult { id, distance })
                .collect()
        } else {
            // Sort all results
            results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));
            results
                .into_iter()
                .map(|(id, distance)| SearchResult { id, distance })
                .collect()
        }
    }
}

